 62→async function exportCookies() {
 63→    const cookies = await session.defaultSession.cookies.get({});
 64→    let content = '# Netscape HTTP Cookie File\n';
 65→    for (const c of cookies) {
 66→        const domain = c.domain.startsWith('.') ? c.domain : '.' + c.domain;
 67→        const flag = 'TRUE';
 68→        const securePath = c.path || '/';
 69→        const secure = c.secure ? 'TRUE' : 'FALSE';
 70→        const expiry = c.expirationDate ? Math.floor(c.expirationDate) : '0';
 71→        content += `${domain}\t${flag}\t${securePath}\t${secure}\t${expiry}\t${c.name}\t${c.value}\n`;
 72→    }
 73→    fs.writeFileSync(COOKIES_FILE, content, 'utf-8');
 74→}
