 35→async function fetchYouTubeInfo(url) {
 36→    return new Promise((resolve) => {
 37→        const cmd = 'yt-dlp';
 38→        const args = ['--dump-json', '--no-playlist', url];
 39→        const process = spawn(cmd, args);
