132→function formatDuration(seconds) {
133→    if (!seconds) return 'N/A';
134→    const hours = Math.floor(seconds / 3600);
135→    const minutes = Math.floor((seconds % 3600) / 60);
136→    const secs = Math.floor(seconds % 60);
137→
138→    if (hours > 0) {
139→        return `${hours}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
140→    }
141→    return `${minutes}:${secs.toString().padStart(2, '0')}`;
142→}
143→
144→function formatViews(count) {
145→    if (!count) return 'N/A';
146→    if (count >= 1000000) return `${(count / 1000000).toFixed(1)}M`;
147→    if (count >= 1000) return `${(count / 1000).toFixed(1)}K`;
148→    return String(count);
149→}
