286→async function downloadDouyinVideo(videoUrl, title) {
287→    const outputDir = getDesktopPath();
288→    const safeName = (title || 'douyin_video').replace(/[<>:"/\\|?*]/g, '_').substring(0, 80);
289→    const filePath = path.join(outputDir, `${safeName}.mp4`);
290→
291→    return new Promise((resolve) => {
292→        const urlObj = new URL(videoUrl);
293→        const client = urlObj.protocol === 'https:' ? https : http;
294→
295→        const reqOptions = {
296→            hostname: urlObj.hostname,
297→            path: urlObj.pathname + urlObj.search,
298→            method: 'GET',
299→            headers: {
300→                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
301→                'Referer': 'https://www.douyin.com/'
302→            }
303→        };
304→
305→        const req = client.request(reqOptions, (res) => {
306→            // 跟随重定向
307→            if (res.statusCode === 301 || res.statusCode === 302) {
308→                const redirectUrl = res.headers.location;
309→                if (redirectUrl) {
310→                    downloadDouyinVideo(redirectUrl, title).then(resolve);
311→                    return;
312→                }
313→            }
314→
315→            if (res.statusCode !== 200) {
316→                resolve({ success: false, error: `HTTP ${res.statusCode}` });
317→                return;
318→            }
319→
320→            const fileStream = fs.createWriteStream(filePath);
321→            let downloaded = 0;
322→            const total = parseInt(res.headers['content-length']) || 0;
323→
324→            res.on('data', (chunk) => {
325→                downloaded += chunk.length;
326→                if (total > 0) {
327→                    mainWindow.webContents.send('download-progress', {
328→                        percent: (downloaded / total) * 100
329→                    });
330→                }
331→            });
332→
333→            res.pipe(fileStream);
334→            fileStream.on('finish', () => {
335→                fileStream.close();
336→                resolve({ success: true, file: filePath });
337→            });
338→            fileStream.on('error', (err) => {
339→                fs.unlink(filePath, () => {});
340→                resolve({ success: false, error: err.message });
341→            });
342→        });
343→
344→        req.on('error', (err) => resolve({ success: false, error: err.message }));
345→        req.setTimeout(60000, () => {
346→            req.destroy();
347→            resolve({ success: false, error: '下载超时' });
348→        });
349→        req.end();
350→    });
351→}
