369→        const proc = spawn(getYtdlp(), args);
370→
371→        let stdout = '';
372→        let stderr = '';
373→
374→        proc.stdout.on('data', (data) => { stdout += data.toString(); });
375→        proc.stderr.on('data', (data) => { stderr += data.toString(); });
376→
377→        proc.on('close', (code) => {
378→            if (code === 0) {
379→                try {
380→                    const info = JSON.parse(stdout);
381→                    const infoText = `📹 标题：${info.title || 'N/A'}
382→
383→👤 频道：${info.channel || info.uploader || 'N/A'}
384→⏱️ 时长：${formatDuration(info.duration)}
385→👁️ 观看：${formatViews(info.view_count)}
386→
387→📅 上传：${info.upload_date ? info.upload_date.substring(0, 10) : 'N/A'}
388→🔗 链接：${info.webpage_url || url}
389→
390→📝 描述：
391→${info.description ? info.description.substring(0, 200) + (info.description.length > 200 ? '...' : '') : '无描述'}`;
392→                    resolve({ success: true, info: infoText });
393→                } catch (e) {
394→                    resolve({ success: false, error: '解析失败' });
395→                }
396→            } else {
397→                resolve({ success: false, error: stderr || '获取信息失败' });
398→            }
399→        });
400→
401→        proc.on('error', () => {
