407→async function downloadYtdlp(url, mode, platform) {
408→    return new Promise((resolve) => {
409→        const outputDir = getDesktopPath();
410→        const outputTemplate = path.join(outputDir, '%(title)s.%(ext)s');
411→        let args = [...baseArgs(platform), '--no-playlist'];
412→
413→        if (mode === 'audio') {
414→            args.push('-f', 'bestaudio', '-x', '--audio-format', 'mp3', '-o', outputTemplate, url);
415→        } else if (mode === 'video') {
416→            args.push('-f', 'bestvideo', '-o', outputTemplate, url);
417→        } else {
418→            args.push('-f', 'bestvideo+bestaudio/best', '--merge-output-format', 'mp4', '-o', outputTemplate, url);
419→        }
420→
421→        const proc = spawn(getYtdlp(), args);
422→        let stderr = '';
423→        let streamCount = 0;
424→        let maxPercent = 0;
425→
426→        proc.stdout.on('data', (data) => {
427→            const output = data.toString();
428→            if (output.includes('Destination:')) {
429→                streamCount++;
430→            }
431→            // 提取最后一个百分比（一次 data 可能包含多个）
432→            const matches = output.match(/(\d+\.?\d*)%/g);
433→            if (matches) {
434→                const lastMatch = matches[matches.length - 1];
435→                let percent = parseFloat(lastMatch);
436→                // 双流下载时：第一个流 0-50%，第二个流 50-100%
437→                if (streamCount >= 2) {
438→                    percent = 50 + percent / 2;
439→                } else if (streamCount === 1 && mode !== 'audio' && mode !== 'video') {
440→                    percent = percent / 2;
441→                }
442→                if (percent > maxPercent) {
443→                    maxPercent = percent;
444→                    mainWindow.webContents.send('download-progress', { percent: maxPercent });
445→                }
446→            }
447→            if (output.includes('Merging') || output.includes('[Merger]')) {
448→                maxPercent = 99;
449→                mainWindow.webContents.send('download-progress', { percent: 99 });
450→            }
451→        });
452→
453→        proc.stderr.on('data', (data) => { stderr += data.toString(); });
454→
455→        proc.on('close', (code) => {
456→            resolve(code === 0 ? { success: true } : { success: false, error: stderr || '下载失败' });
457→        });
458→
459→        proc.on('error', () => {
460→            resolve({ success: false, error: 'yt-dlp 未安装，请先安装 yt-dlp' });
461→        });
462→    });
463→}
