467→function cleanUrl(url) {
468→    const match = url.match(/https?:\/\/[^\s"'<>]+/);
469→    return match ? match[0] : url.trim();
470→}
471→
472→ipcMain.handle('extract-info', async (event, url) => {
473→    url = cleanUrl(url);
474→    const platform = detectPlatform(url);
475→    if (platform === 'unknown') return { success: false, error: '不支持的平台 URL' };
476→
477→    if (platform === 'douyin') {
478→        return await extractDouyinInfo(url);
479→    }
480→    return await extractYtdlpInfo(url, platform);
481→});
482→
483→ipcMain.handle('start-download', async (event, url, mode) => {
484→    url = cleanUrl(url);
485→    const platform = detectPlatform(url);
486→    if (platform === 'unknown') return { success: false, error: '不支持的平台 URL' };
487→
488→    if (platform === 'douyin') {
489→        // 先提取视频信息获取下载链接
490→        const info = await extractDouyinInfo(url);
491→        if (!info.success || !info._videoUrl) {
492→            return { success: false, error: info.error || '无法获取抖音视频下载链接' };
493→        }
494→        return await downloadDouyinVideo(info._videoUrl, info._title);
495→    }
496→    return await downloadYtdlp(url, mode, platform);
497→});
