501→        await warmupCookies();
502→        return { success: true };
503→    } catch (err) {
504→        return { success: false, error: err.message };
505→    }
506→});
507→
508→// ============= 工具函数 =============
509→
510→function formatDuration(seconds) {
511→    if (!seconds) return 'N/A';
512→    const hours = Math.floor(seconds / 3600);
513→    const minutes = Math.floor((seconds % 3600) / 60);
514→    const secs = Math.floor(seconds % 60);
515→    if (hours > 0) {
516→        return `${hours}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
517→    }
518→    return `${minutes}:${secs.toString().padStart(2, '0')}`;
519→}
520→
521→function formatViews(count) {
522→    if (!count) return 'N/A';
523→    if (count >= 1000000) return `${(count / 1000000).toFixed(1)}M`;
524→    if (count >= 1000) return `${(count / 1000).toFixed(1)}K`;
525→    return String(count);
526→}
