/**
 * 用隐藏窗口加载抖音视频页面，注入 JS 提取视频数据
 */
async function extractDouyinData(url) {
    return new Promise((resolve, reject) => {
        const win = new BrowserWindow({
            width: 800, height: 600,
            show: false,
            webPreferences: { nodeIntegration: false, contextIsolation: true }
        });

        const timeout = setTimeout(() => {
            win.destroy();
            reject(new Error('抖音页面加载超时'));
        }, 20000);

        win.webContents.on('did-finish-load', () => {
            setTimeout(async () => {
                try {
                    const data = await win.webContents.executeJavaScript(`
                        (function() {
                            try {
                                // 方法1: __UNIVERSAL_DATA_FOR_REHYDRATION__
                                var el = document.getElementById('RENDER_DATA');
                                if (el) {
                                    var decoded = decodeURIComponent(el.textContent);
                                    return { method: 'RENDER_DATA', data: decoded };
                                }

                                // 方法2: RENDER_DATA 不存在时尝试 SSR_HYDRATED_DATA
                                var scripts = document.querySelectorAll('script');
                                for (var i = 0; i < scripts.length; i++) {
                                    var text = scripts[i].textContent || '';
                                    if (text.includes('window._SSR_HYDRATED_DATA')) {
                                        var match = text.match(/window\\._SSR_HYDRATED_DATA\\s*=\\s*(\\{.+?\\})\\s*;?\\s*$/s);
                                        if (match) return { method: 'SSR', data: match[1] };
                                    }
                                }

                                // 方法3: 直接找 video 标签
                                var video = document.querySelector('video source');
                                if (video && video.src) {
                                    return { method: 'video_tag', videoUrl: video.src, title: document.title };
                                }
                                var videoEl = document.querySelector('video');
                                if (videoEl && videoEl.src) {
                                    return { method: 'video_tag', videoUrl: videoEl.src, title: document.title };
                                }

                                return { method: 'none', html: document.title };
                            } catch(e) {
                                return { method: 'error', error: e.message };
                            }
                        })()
                    `);

                    clearTimeout(timeout);
                    win.destroy();
                    resolve(data);
                } catch (err) {
                    clearTimeout(timeout);
                    win.destroy();
                    reject(err);
                }
            }, 3000);
        });

        win.loadURL(url).catch(err => {
            clearTimeout(timeout);
            win.destroy();
            reject(err);
        });
    });
}

/**
 * 从抖音页面数据中解析视频信息
 */
function parseDouyinData(rawData) {
    try {
        if (rawData.method === 'video_tag') {
            return {
                title: rawData.title || '抖音视频',
                videoUrl: rawData.videoUrl,
                desc: rawData.title || ''
            };
        }

        const data = JSON.parse(rawData.data);

        // RENDER_DATA 格式
        if (rawData.method === 'RENDER_DATA') {
            // 遍历所有 key 找视频数据
            for (const key of Object.keys(data)) {
                const section = data[key];
                // 查找 aweme detail
                const detail = section?.awemeDetail || section?.videoInfoRes?.item_list?.[0];
                if (detail) {
                    const video = detail.video || {};
                    const playAddr = video.play_addr || video.playAddr || {};
                    const urlList = playAddr.url_list || [];
                    const videoUrl = urlList[0] || video.download_addr?.url_list?.[0];
                    return {
                        title: detail.desc || '抖音视频',
                        desc: detail.desc || '',
                        author: detail.author?.nickname || '',
                        duration: video.duration ? video.duration / 1000 : 0,
                        videoUrl: videoUrl
                    };
                }
            }
        }

        // SSR 格式
        if (rawData.method === 'SSR') {
            const detail = data?.anyVideo?.videoInfoRes?.item_list?.[0] ||
                          data?.videoDetail?.videoInfo;
            if (detail) {
                const video = detail.video || {};
                const playAddr = video.play_addr || {};
                const urlList = playAddr.url_list || [];
                return {
                    title: detail.desc || '抖音视频',
                    desc: detail.desc || '',
                    author: detail.author?.nickname || '',
                    videoUrl: urlList[0]
                };
            }
        }

        return null;
    } catch (e) {
        console.error('解析抖音数据失败:', e.message);
        return null;
    }
}

async function extractDouyinInfo(url) {
    try {
        const rawData = await extractDouyinData(url);
        const parsed = parseDouyinData(rawData);
        if (parsed) {
            let infoText = `📹 标题：${parsed.title || 'N/A'}`;
            if (parsed.author) infoText += `\n\n👤 作者：${parsed.author}`;
            if (parsed.duration) infoText += `\n⏱️ 时长：${formatDuration(parsed.duration)}`;
            if (parsed.desc) infoText += `\n\n📝 描述：\n${parsed.desc.substring(0, 200)}`;
            return { success: true, info: infoText, _videoUrl: parsed.videoUrl, _title: parsed.title };
        }
        return { success: false, error: '无法解析抖音视频数据' };
    } catch (err) {
        return { success: false, error: err.message };
    }
}

async function downloadDouyinVideo(videoUrl, title) {
    const outputDir = getDesktopPath();
    const safeName = (title || 'douyin_video').replace(/[<>:"/\\|?*]/g, '_').substring(0, 80);
    const filePath = path.join(outputDir, `${safeName}.mp4`);

    return new Promise((resolve) => {
        const urlObj = new URL(videoUrl);
        const client = urlObj.protocol === 'https:' ? https : http;

        const reqOptions = {
            hostname: urlObj.hostname,
            path: urlObj.pathname + urlObj.search,
            method: 'GET',
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
                'Referer': 'https://www.douyin.com/'
            }
        };

        const req = client.request(reqOptions, (res) => {
            // 跟随重定向
            if (res.statusCode === 301 || res.statusCode === 302) {
                const redirectUrl = res.headers.location;
                if (redirectUrl) {
                    downloadDouyinVideo(redirectUrl, title).then(resolve);
                    return;
                }
            }

            if (res.statusCode !== 200) {
                resolve({ success: false, error: `HTTP ${res.statusCode}` });
                return;
            }

            const fileStream = fs.createWriteStream(filePath);
            let downloaded = 0;
            const total = parseInt(res.headers['content-length']) || 0;

            res.on('data', (chunk) => {
                downloaded += chunk.length;
                if (total > 0) {
                    mainWindow.webContents.send('download-progress', {
                        percent: (downloaded / total) * 100
                    });
                }
            });

            res.pipe(fileStream);
            fileStream.on('finish', () => {
                fileStream.close();
                resolve({ success: true, file: filePath });
            });
            fileStream.on('error', (err) => {
                fs.unlink(filePath, () => {});
                resolve({ success: false, error: err.message });
            });
        });

        req.on('error', (err) => resolve({ success: false, error: err.message }));
        req.setTimeout(60000, () => {
            req.destroy();
            resolve({ success: false, error: '下载超时' });
        });
        req.end();
    });
}

